import{_ as i,o as t,i as s,ad as a}from"./chunks/framework.Cq4hg8jX.js";const u=JSON.parse('{"title":"Unplugin","description":"Configure PikaCSS with any bundler using the universal unplugin integration.","frontmatter":{"title":"Unplugin","description":"Configure PikaCSS with any bundler using the universal unplugin integration.","relatedPackages":["@pikacss/unplugin-pikacss"],"relatedSources":["packages/unplugin/src/index.ts","packages/unplugin/src/types.ts"],"category":"integrations","order":10},"headers":[],"relativePath":"integrations/unplugin.md","filePath":"integrations/unplugin.md"}'),n={name:"integrations/unplugin.md"};function o(d,e,r,l,p,c){return t(),s("div",null,[...e[0]||(e[0]=[a(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /integrations/unplugin.md for this page in Markdown format</div><h1 id="unplugin" tabindex="-1">Unplugin <a class="header-anchor" href="#unplugin" aria-label="Permalink to “Unplugin”">​</a></h1><p>PikaCSS uses <a href="https://github.com/unjs/unplugin" target="_blank" rel="noreferrer">unplugin</a> to provide a single build plugin that works across all major bundlers.</p><p>The Vite entry supports Vite 7 and 8 only.</p><h2 id="supported-tools" tabindex="-1">Supported Tools <a class="header-anchor" href="#supported-tools" aria-label="Permalink to “Supported Tools”">​</a></h2><table tabindex="0"><thead><tr><th>Bundler</th><th>Import Path</th></tr></thead><tbody><tr><td>Vite</td><td><code>@pikacss/unplugin-pikacss/vite</code></td></tr><tr><td>Webpack</td><td><code>@pikacss/unplugin-pikacss/webpack</code></td></tr><tr><td>Rspack</td><td><code>@pikacss/unplugin-pikacss/rspack</code></td></tr><tr><td>esbuild</td><td><code>@pikacss/unplugin-pikacss/esbuild</code></td></tr><tr><td>Rollup</td><td><code>@pikacss/unplugin-pikacss/rollup</code></td></tr><tr><td>Rolldown</td><td><code>@pikacss/unplugin-pikacss/rolldown</code></td></tr></tbody></table><p>Example with Vite:</p><div class="language-ts"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// vite.config.ts</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PikaCSS </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@pikacss/unplugin-pikacss/vite&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { defineConfig } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;vite&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> default</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> defineConfig</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  plugins: [</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    PikaCSS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      // options</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Vite plugin order</p><p>The Vite entry registers with <code>enforce: &#39;pre&#39;</code>. PikaCSS still runs before framework compiler plugins even if your Vite <code>plugins</code> array is ordered as <code>[vue(), pikacss()]</code>, so you do not need to reorder the array just to avoid template compile errors.</p></div><h2 id="config" tabindex="-1">Config <a class="header-anchor" href="#config" aria-label="Permalink to “Config”">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Description</th></tr></thead><tbody><tr><td>cwd</td><td>Explicit working directory for path resolution. Overrides the bundler-detected project root.</td></tr><tr><td>scan</td><td>File glob patterns controlling which source files are scanned for <code>pika()</code> call sites. When <code>scan.include</code> is not set, the default covers <code>**/*.{js,mjs,cjs,jsx,ts,mts,cts,tsx,vue}</code>; the default <code>exclude</code> skips <code>node_modules</code>, <code>dist</code>, <code>.git</code>, <code>.nuxt</code>, <code>.output</code>, and <code>coverage</code>.</td></tr><tr><td>config</td><td>PikaCSS engine configuration, either as an inline object or a path to a config module. When omitted, a config file is discovered in the project root only (candidates <code>pika.config.*</code> then <code>pikacss.config.*</code>, TS variants first).</td></tr><tr><td>autoCreateConfig</td><td>When <code>true</code>, auto-creates a <code>pika.config.js</code> file if none is found. Default: <code>false</code> — a build plugin should not write files into your repo; create a config yourself or opt in.</td></tr><tr><td>fnName</td><td>Function identifier the scanner looks for when extracting call sites. Default: <code>&#39;pika&#39;</code>.</td></tr><tr><td>transformedFormat</td><td>Output shape of transformed <code>pika()</code> calls: <code>&#39;string&#39;</code> or <code>&#39;array&#39;</code>.</td></tr><tr><td>tsCodegen</td><td>Controls TypeScript type-definition code generation.</td></tr><tr><td>cssCodegen</td><td>Controls CSS code-generation output. CSS codegen cannot be fully disabled.</td></tr><tr><td>report</td><td>Emit a design-token usage report at the end of a production build. <code>true</code> logs a summary; <code>{ output }</code> also writes the full report as JSON.</td></tr></tbody></table><blockquote><p>See <a href="/api/unplugin.html">API Reference — Unplugin</a> for full type signatures and defaults.</p></blockquote><h2 id="diagnostics-and-reporting" tabindex="-1">Diagnostics and Reporting <a class="header-anchor" href="#diagnostics-and-reporting" aria-label="Permalink to “Diagnostics and Reporting”">​</a></h2><p>Engine plugins can report diagnostics during transforms (for example, <a href="/official-plugins/design-tokens.html#strict-mode"><code>@pikacss/plugin-design-tokens</code></a> strict mode). The engine never throws them — it hands each <code>Diagnostic</code> (<code>{ level, code, message, plugin?, … }</code>) to a handler. The unplugin installs that handler for you; there is no <code>onDiagnostic</code> plugin option to set.</p><h3 id="how-diagnostics-surface" tabindex="-1">How diagnostics surface <a class="header-anchor" href="#how-diagnostics-surface" aria-label="Permalink to “How diagnostics surface”">​</a></h3><p>The built-in handler logs <strong>every</strong> diagnostic live, so a <code>&#39;warning&#39;</code> appears immediately during dev and build. It also collects the <code>&#39;error&#39;</code>-level diagnostics and, once every module has been transformed, throws a single aggregated <code>Error</code> at <code>buildEnd</code> listing them all — so an error-severity diagnostic <strong>fails a production build</strong>.</p><div class="info custom-block"><p class="custom-block-title">Why the build fails at <code>buildEnd</code>, not inline</p><p>Core delivers diagnostics through a handler whose throws are swallowed, so a handler cannot abort a single module&#39;s transform. Errors are therefore aggregated and thrown once at <code>buildEnd</code>. The trade-off: an error surfaces after the full build rather than inline on the producing module (with Vite&#39;s dev overlay). Warnings still log live on the module that produced them.</p></div><h3 id="report" tabindex="-1"><code>report</code> <a class="header-anchor" href="#report" aria-label="Permalink to “report”">​</a></h3><p><code>report</code> emits a design-token usage report at the end of a production build. It requires <code>@pikacss/plugin-design-tokens</code> to be registered and is a no-op otherwise. <code>true</code> logs a concise summary (total tokens, used/unused counts, deprecated tokens in use, and strict-violation counts) once per build. Passing <code>{ output }</code> additionally writes the full report as JSON to that path, resolved against the project root. The report is emitted only in build mode, so a dev server never spams it per HMR update:</p><div class="language-ts"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">PikaCSS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  report: { output: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;./design-tokens.report.json&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Nuxt</p><p>The Nuxt module mirrors the unplugin options, so <code>report</code> works the same way in a Nuxt project. See <a href="/integrations/nuxt.html">Nuxt</a>.</p></div><h2 id="typescript-and-import-pika-css" tabindex="-1">TypeScript and <code>import &#39;pika.css&#39;</code> <a class="header-anchor" href="#typescript-and-import-pika-css" aria-label="Permalink to “TypeScript and import &#39;pika.css&#39;”">​</a></h2><p>In Vite projects, the ambient <code>*.css</code> module declaration from <code>vite/client</code> covers the <code>pika.css</code> specifier. PikaCSS itself ships no ambient declaration for it, so TypeScript projects on other bundlers (webpack, Rspack, esbuild) may report <code>TS2307: Cannot find module &#39;pika.css&#39;</code>. Add a two-line shim to any <code>.d.ts</code> file in your program:</p><div class="language-ts"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// pika-css.d.ts</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">declare</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> module</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;pika.css&#39;</span></span></code></pre></div><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to “Next”">​</a></h2><ul><li><a href="/integrations/nuxt.html">Nuxt</a> — zero-config Nuxt integration.</li><li><a href="/getting-started/setup.html">Setup</a> — basic project setup.</li></ul>`,26)])])}const g=i(n,[["render",o]]);export{u as __pageData,g as default};
